function safeJSONParse(str, fallback) {
  try { return JSON.parse(str) || fallback; }
  catch (e) { return fallback; }
}

function esc(str) {
  if (typeof str !== 'string') return '';
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

const savedIntroPages = safeJSONParse(localStorage.getItem('ka_admin_intro_pages'), null);
window.INTRO_PAGES = savedIntroPages && savedIntroPages.length === 7 ? savedIntroPages : DEFAULT_INTRO_PAGES;

function renderFrontendIntroPages() {
  const stage = document.getElementById('stage');
  if (!stage) return;
  
  let html = '';
  window.INTRO_PAGES.forEach((page, i) => {
    if (i === 0) {
      html += `
      <div class="chapter chapter-intro active" data-chapter="0">
        <div class="chapter-inner">
          <div class="intro-logo">KA</div>
          <h1 class="intro-title" data-en='${page.labelEn}' data-ar='${page.labelAr}'>${page.labelEn}</h1>
          <p class="intro-sub" data-en="${page.subEn}" data-ar="${page.subAr}">${page.subEn}</p>
        </div>
      </div>`;
    } else if (i === 6) {
      html += `
      <div class="chapter chapter-final" data-chapter="6">
        <div class="chap-glow"></div>
        <div class="chapter-inner">
          <div class="chap-label">
            <div class="chap-label-line"></div>
            <span data-en="${page.labelEn}" data-ar="${page.labelAr}">${page.labelEn}</span>
            <div class="chap-label-line"></div>
          </div>
          <h2 class="final-title" data-en='${page.phraseEn}' data-ar='${page.phraseAr}'>${page.phraseEn}</h2>
          <button class="final-cta" onclick="enterSite()">
            <span data-en="${page.ctaEn}" data-ar="${page.ctaAr}">${page.ctaEn}</span>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M5 12h14"/><path d="M12 5l7 7-7 7"/></svg>
          </button>
        </div>
      </div>`;
    } else {
      html += `
      <div class="chapter" data-chapter="${i}">
        <div class="chap-glow"></div>
        <div class="chapter-inner">
          <div class="chap-label">
            <div class="chap-label-line"></div>
            <span data-en="${page.labelEn}" data-ar="${page.labelAr}">${page.labelEn}</span>
            <div class="chap-label-line"></div>
          </div>
          <div class="chap-number"><span class="num-counter" data-target="${page.number}">0</span><span class="num-suffix" data-en="${page.suffixEn}" data-ar="${page.suffixAr}">${page.suffixEn}</span></div>
          <p class="chap-phrase" data-en='${page.phraseEn}' data-ar='${page.phraseAr}'>${page.phraseEn}</p>
          <div class="chap-sub" data-en="${page.subEn}" data-ar="${page.subAr}">${page.subEn}</div>
        </div>
      </div>`;
    }
  });
  stage.innerHTML = html;
}
renderFrontendIntroPages();


(function () {
  const PHOTO =
    "data:image/jpeg;base64,";
  document.getElementById("photoRevealImg").style.backgroundImage =
    `url('${PHOTO}')`;

  const TOTAL_CHAPTERS = 7; // 0 to 6
  const PHOTO_CHAPTERS = [1, 2]; // chapters where photo subtly visible
  let currentChapter = 0;

  // Build rail labels
  const railLabels = document.getElementById("railLabels");
  const labelTexts = [
    { en: "Welcome", ar: "مرحباً" },
    { en: "Begin", ar: "البداية" },
    { en: "Craft", ar: "الحرفة" },
    { en: "Trust", ar: "الثقة" },
    { en: "Reach", ar: "المدى" },
    { en: "Giveback", ar: "العطاء" },
    { en: "Enter", ar: "الدخول" },
  ];
  labelTexts.forEach((lt, i) => {
    const lbl = document.createElement("div");
    lbl.className = "rail-label";
    lbl.dataset.en = lt.en;
    lbl.dataset.ar = lt.ar;
    lbl.textContent = lt.en;
    if (i === 0) lbl.classList.add("active");
    railLabels.appendChild(lbl);
  });

  // Determine current chapter from scroll position
  function getChapterFromScroll() {
    const scrollY = window.scrollY;
    const docHeight =
      document.documentElement.scrollHeight - window.innerHeight;
    const progress = Math.max(0, Math.min(1, scrollY / docHeight));
    // Map progress (0-1) to chapter (0 to TOTAL_CHAPTERS-1)
    const chapterIndex = Math.min(
      TOTAL_CHAPTERS - 1,
      Math.floor(progress * TOTAL_CHAPTERS),
    );
    return { chapterIndex, progress };
  }

  let lastChapter = -1;
  function update() {
    const { chapterIndex, progress } = getChapterFromScroll();

    // Update rail fill
    document.getElementById("railFill").style.height = progress * 100 + "%";

    // Update counter
    const counter = document.getElementById("chapterCurrent");
    const num = String(chapterIndex + 1).padStart(2, "0");
    const lang = document.documentElement.lang || 'en';
    counter.textContent = lang === 'ar' ? num.replace(/[0-9]/g, d => '٠١٢٣٤٥٦٧٨٩'[d]) : num;

    // Update labels
    document.querySelectorAll(".rail-label").forEach((lbl, i) => {
      lbl.classList.toggle("active", i === chapterIndex);
    });

    // Hide scroll hint after first scroll
    const hint = document.getElementById("scrollHint");
    if (window.scrollY > 100) hint.classList.add("hide");
    else hint.classList.remove("hide");

    // Photo reveal
    const photoReveal = document.getElementById("photoReveal");
    photoReveal.classList.toggle("show", PHOTO_CHAPTERS.includes(chapterIndex));

    const chap1NavyBg = document.getElementById("chap1NavyBg");
    if (chap1NavyBg) {
      chap1NavyBg.classList.toggle("show", chapterIndex === 1);
    }

    // Switch chapter only if changed
    if (chapterIndex !== lastChapter) {
      const oldChapter = lastChapter;
      lastChapter = chapterIndex;
      currentChapter = chapterIndex;
      
      const skipBtn = document.getElementById("welcomeSkipBtn");
      const floatingLangBtn = document.getElementById("floatingLangBtn");
      if (skipBtn) {
        if (chapterIndex === 6) {
          skipBtn.classList.add("hidden-on-mobile");
          if (floatingLangBtn) floatingLangBtn.classList.add("hidden-on-mobile");
        } else {
          skipBtn.classList.remove("hidden-on-mobile");
          if (floatingLangBtn) floatingLangBtn.classList.remove("hidden-on-mobile");
        }
      }

      // Hide all chapters, then activate target
      document.querySelectorAll(".chapter").forEach((c, i) => {
        c.classList.remove("active");
        // Reset any inline transforms
        c.classList.remove("exit-up", "exit-down");
      });
      const target = document.querySelector(`[data-chapter="${chapterIndex}"]`);
      if (target) {
        target.classList.add("active");
        // Trigger number animation
        const counterEl = target.querySelector(".num-counter");
        if (counterEl) animateCounter(counterEl);
      }
    }
  }

  function animateCounter(el) {
    // Avoid re-triggering if already animated for this view
    if (el.dataset.animating === "1") return;
    el.dataset.animating = "1";
    const target = parseInt(el.dataset.target, 10);
    const duration = 1600;
    const start = Date.now();
    el.textContent = "0";
    function tick() {
      const elapsed = Date.now() - start;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      const value = Math.floor(target * eased);
      el.textContent = value.toLocaleString();
      if (progress < 1) requestAnimationFrame(tick);
      else {
        el.textContent = target.toLocaleString();
        // Allow re-animation if user scrolls back and forward
        setTimeout(() => {
          el.dataset.animating = "0";
        }, 200);
      }
    }
    setTimeout(tick, 350);
  }

  function enterSite() {
    document.body.style.transition = "opacity .6s ease";
    document.body.style.opacity = "0";
    setTimeout(() => {
      try {
        localStorage.setItem("intro_done", "1");
      } catch (e) {}
      window.location.href = "portfolio.html";
    }, 600);
  }

  // Throttle scroll handler
  let scrolling = false;
  window.addEventListener(
    "scroll",
    () => {
      if (!scrolling) {
        requestAnimationFrame(() => {
          update();
          scrolling = false;
        });
        scrolling = true;
      }
    },
    { passive: true },
  );

  // Language toggle
  const langBtn = document.getElementById("langBtn");
  const floatingLangBtn = document.getElementById("floatingLangBtn");
  let currentLang = "en";
  
  const toggleLanguage = () => {
    currentLang = currentLang === "en" ? "ar" : "en";
    document.documentElement.lang = currentLang;
    document.documentElement.dir = currentLang === "ar" ? "rtl" : "ltr";
    
    const nextLangText = currentLang === "en" ? "العربية" : "English";
    if (langBtn) langBtn.textContent = nextLangText;
    if (floatingLangBtn) floatingLangBtn.textContent = nextLangText;
    
    document.querySelectorAll("[data-en]").forEach((el) => {
      const txt = el.getAttribute("data-" + currentLang);
      if (!txt) return;
      if (txt.includes("<")) el.innerHTML = txt;
      else el.textContent = txt;
    });

    document.querySelectorAll("[data-en-placeholder]").forEach((el) => {
      const txt = el.getAttribute("data-" + currentLang + "-placeholder");
      if (txt) {
        el.placeholder = txt;
      }
    });

    window.dispatchEvent(new Event('scroll'));
  };

  if (langBtn) langBtn.addEventListener("click", toggleLanguage);
  if (floatingLangBtn) floatingLangBtn.addEventListener("click", toggleLanguage);

  // Init
  update();
})();

