// ═══════════ TRANSITION FROM WELCOME TO PORTFOLIO ═══════════
// Override enterSite to swap sections instead of redirecting
window.enterSite = function () {
  const body = document.body;

  // Create overlay for smooth transition to avoid WebKit blur glitch
  const overlay = document.createElement("div");
  overlay.style.position = "fixed";
  overlay.style.inset = "0";
  overlay.style.background = "#050814"; // Match the dark background
  overlay.style.zIndex = "999999";
  overlay.style.opacity = "0";
  overlay.style.transition = "opacity .5s ease";
  body.appendChild(overlay);

  // Force reflow and start fade in
  overlay.offsetHeight;
  overlay.style.opacity = "1";

  setTimeout(() => {
    document.getElementById("welcome-section").classList.add("hidden");
    document.getElementById("portfolio-section").classList.add("visible");
    body.classList.add("in-portfolio");
    window.scrollTo(0, 0);

    // Fade out overlay
    overlay.style.opacity = "0";
    setTimeout(() => overlay.remove(), 500);

    // Save flag to sessionStorage so welcome doesn't show again in this session
    try {
      sessionStorage.setItem("intro_done", "1");
    } catch (e) {}
    // Activate home page by default
    spaGo("home", true);
    window.dispatchEvent(new Event("resize"));
    window.dispatchEvent(new Event("scroll"));
  }, 500);
};

// On page load — check if intro was already done in THIS session, skip welcome
(function () {
  try {
    // Clean up old localStorage flag (one-time migration)
    localStorage.removeItem("intro_done");
    if (sessionStorage.getItem("intro_done") === "1") {
      // Skip welcome entirely
      const welcomeSection = document.getElementById("welcome-section");
      const portfolioSection = document.getElementById("portfolio-section");
      if (welcomeSection && portfolioSection) {
        welcomeSection.classList.add("hidden");
        portfolioSection.classList.add("visible");
        document.body.classList.add("in-portfolio");
        // Apply home page or page from hash
        const hash = window.location.hash.replace("#", "");
        const validPages = ["home", "about", "services", "training", "contact"];
        const targetPage = validPages.includes(hash) ? hash : "home";
        // Wait for spaGo to be defined
        const tryActivate = () => {
          if (typeof window.spaGo === "function") {
            window.spaGo(targetPage, true);
          } else {
            setTimeout(tryActivate, 50);
          }
        };
        tryActivate();
      }
    }
  } catch (e) {}
})();

