// ═══════════ SPA MULTI-PAGE NAVIGATION ═══════════
window.spaGo = function (page, skipScroll) {
  if (page !== "admin" && page !== "admin-login") {
    document.body.classList.remove("admin-mode");
    document.documentElement.classList.remove("admin-mode");
  }

  // Hide all pages
  document.querySelectorAll("section[data-page]").forEach((s) => {
    s.classList.remove("spa-active");
  });
  // Show all sections matching this page
  const targets = document.querySelectorAll(
    'section[data-page="' + page + '"]',
  );
  targets.forEach((s) => s.classList.add("spa-active"));

  // Update nav active state
  document.querySelectorAll(".nav-links a[data-spa]").forEach((a) => {
    a.classList.toggle("spa-current", a.getAttribute("data-spa") === page);
  });

  // Update URL hash (without triggering navigation)
  if (!skipScroll) {
    try {
      history.replaceState(null, "", "#" + page);
    } catch (e) {}
    window.scrollTo({ top: 0, behavior: "auto" });
  }

  // FORCE all .reveal elements in active sections to show
  setTimeout(() => {
    targets.forEach((s) => {
      s.querySelectorAll(".reveal").forEach((el) => el.classList.add("in"));
    });
    window.dispatchEvent(new Event("resize"));
    window.dispatchEvent(new Event("scroll"));
    if (page === "about") {
      setTimeout(() => {
        if (typeof window.initWorldMap === "function") {
          window.initWorldMap();
        }
      }, 300);
    }
  }, 50);
};

// On load — check hash and go to that page if in portfolio mode
window.addEventListener("DOMContentLoaded", function () {
  // If hash exists and welcome is hidden, navigate
  const hash = window.location.hash.replace("#", "");
  const validPages = ["home", "about", "services", "training", "contact"];
  if (
    validPages.includes(hash) &&
    document.body.classList.contains("in-portfolio")
  ) {
    spaGo(hash, true);
  }
});

// Handle browser back/forward
window.addEventListener("hashchange", function () {
  const hash = window.location.hash.replace("#", "");
  const validPages = ["home", "about", "services", "training", "contact", "admin", "admin-login"];
  if (
    validPages.includes(hash) &&
    document.body.classList.contains("in-portfolio")
  ) {
    spaGo(hash, true);
  }
});

// ═══════ ABOUT STORYTELLING — SCROLL DRIVEN ═══════
(function () {
  // Set photos on story-photo-bg elements
  const photoEls = document.querySelectorAll("#storyPhoto1, #storyPhoto2");
  if (photoEls.length > 0 && typeof PHOTO !== "undefined") {
    photoEls.forEach((el) => {
      el.style.backgroundImage = `url('${PHOTO}')`;
    });
  }

  const stage = document.querySelector(".story-stage");
  if (!stage) return;
  let chapters = stage.querySelectorAll(".story-chapter");
  const aboutSection = document.getElementById("about");

  // Journey line elements
  const journeyProgress = document.getElementById("journeyProgress");
  const journeyTip = document.getElementById("journeyTip");
  let journeyNodes = stage.querySelectorAll(".journey-node");
  const journeyTrack = stage.querySelector(".journey-line-track");

  // Track which chapters have been "reached" (for glow effect — once only)
  const reachedChapters = new WeakSet();
  
  window.updateStoryScrollNodes = function() {
    chapters = stage.querySelectorAll(".story-chapter");
    journeyNodes = stage.querySelectorAll(".journey-node");
    positionJourneyNodes();
    onScroll();
  };

  // Position nodes at each chapter's center (last node at chapter top for clean ending)
  function positionJourneyNodes() {
    const stageRect = stage.getBoundingClientRect();
    const zoomScale = parseFloat(getComputedStyle(document.documentElement).zoom) || 1;
    const lastIdx = chapters.length - 1;
    let firstNodeTop = null;
    let lastNodeTop = null;
    chapters.forEach((chap, idx) => {
      const node = journeyNodes[idx];
      if (!node) return;
      const chapRect = chap.getBoundingClientRect();
      // Adjust for zoom scaling: bounding rect returns actual screen coords, we need to un-scale it for CSS top
      let top = ((chapRect.top - stageRect.top) / zoomScale) - 30;
      node.style.top = top + "px";
      if (firstNodeTop === null) firstNodeTop = top;
      lastNodeTop = top;
    });
    // Make track span from first node to last node
    if (journeyTrack && firstNodeTop !== null && lastNodeTop !== null) {
      journeyTrack.style.top = firstNodeTop + "px";
      journeyTrack.style.height = lastNodeTop - firstNodeTop + "px";
    }
  }
  // Position on load and on resize
  setTimeout(positionJourneyNodes, 200);
  window.addEventListener("resize", positionJourneyNodes);

  // Also observe stage resize to handle late font/image loading causing layout shifts
  if (typeof ResizeObserver !== "undefined") {
    const observer = new ResizeObserver(() => {
      positionJourneyNodes();
    });
    observer.observe(stage);
  }

  // Track which counters have animated
  const animatedCounters = new WeakSet();

  function animateCount(el) {
    if (animatedCounters.has(el)) return;
    animatedCounters.add(el);
    const target = parseInt(el.dataset.countTarget, 10);
    const duration = 1600;
    const start = performance.now();
    function tick(now) {
      const elapsed = now - start;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      const val = Math.floor(target * eased);
      el.textContent = val.toLocaleString();
      if (progress < 1) requestAnimationFrame(tick);
      else el.textContent = target.toLocaleString() + "+";
    }
    requestAnimationFrame(tick);
  }

  function onScroll() {
    // Only run logic if about page is active
    if (!aboutSection.classList.contains("spa-active")) return;

    const winH = window.innerHeight;

    // === JOURNEY LINE PROGRESS ===
    // Use first and last node positions as the line bounds
    const firstNode = journeyNodes[0];
    const lastNode = journeyNodes[journeyNodes.length - 1];
    if (firstNode && lastNode && journeyProgress && journeyTip) {
      const firstNodeTop = parseFloat(firstNode.style.top) || 0;
      const lastNodeTop = parseFloat(lastNode.style.top) || 0;
      const lineLengthPx = lastNodeTop - firstNodeTop;

      // Calculate how far scrolled past the first node (in stage-local coords)
      const zoomScale = parseFloat(getComputedStyle(document.documentElement).zoom) || 1;
      const stageRect = stage.getBoundingClientRect();
      const viewportCenter = (winH / zoomScale) / 2;
      const scrolledIntoStage = viewportCenter - (stageRect.top / zoomScale);
      const scrolledFromFirstNode = scrolledIntoStage - firstNodeTop;

      // Progress 0 → 1
      const progress = Math.max(
        0,
        Math.min(1, scrolledFromFirstNode / lineLengthPx),
      );
      journeyProgress.style.top = firstNodeTop + "px";
      journeyProgress.style.height = progress * lineLengthPx + "px";

      // Tip position
      const tipTop = firstNodeTop + progress * lineLengthPx;
      journeyTip.style.top = tipTop + "px";

      // Hide tip when fully at the last node (clean ending)
      if (progress >= 1) journeyTip.style.opacity = "0";
      else if (progress <= 0) journeyTip.style.opacity = "0";
      else journeyTip.style.opacity = "1";
    }

    // Activate journey nodes as we pass them
    journeyNodes.forEach((node, idx) => {
      const nodeTop = parseFloat(node.style.top) || 0;
      const zoomScale = parseFloat(getComputedStyle(document.documentElement).zoom) || 1;
      const stageRect = stage.getBoundingClientRect();
      const viewportCenter = (winH / zoomScale) / 2;
      const scrolledIntoStage = viewportCenter - (stageRect.top / zoomScale);
      if (scrolledIntoStage >= nodeTop - 50) {
        if (!node.classList.contains("passed")) {
          node.classList.add("passed");
        }
      } else {
        node.classList.remove("passed");
      }
    });

    chapters.forEach((chap, idx) => {
      const r = chap.getBoundingClientRect();
      const inView = r.top < winH * 0.75 && r.bottom > winH * 0.25;
      if (inView) {
        chap.classList.add("active");
        // Reveal all elements
        chap
          .querySelectorAll(".reveal-story")
          .forEach((el) => el.classList.add("in"));
        // Animate counters
        chap.querySelectorAll("[data-count-target]").forEach((el) => {
          const r2 = el.getBoundingClientRect();
          if (r2.top < winH * 0.85) animateCount(el);
        });

        // GLOW EFFECT — fires once when chapter is first reached
        if (!reachedChapters.has(chap)) {
          reachedChapters.add(chap);
          chap.classList.add("just-reached");
          setTimeout(() => chap.classList.remove("just-reached"), 2000);
        }
      }
    });
  }

  // Throttled scroll listener
  let scheduled = false;
  function handleScroll() {
    if (!scheduled) {
      scheduled = true;
      requestAnimationFrame(() => {
        onScroll();
        scheduled = false;
      });
    }
  }
  window.addEventListener("scroll", handleScroll, { passive: true });
  window.addEventListener("resize", handleScroll);

  // Also trigger on page change
  const observer = new MutationObserver(() => {
    if (aboutSection.classList.contains("spa-active")) {
      setTimeout(onScroll, 100);
    }
  });
  observer.observe(aboutSection, {
    attributes: true,
    attributeFilter: ["class"],
  });

  // Initial trigger
  setTimeout(onScroll, 200);
})();

// ═══════ QUICK BRIEF MODAL ═══════
(function () {
  // CONFIG — Update these with your real contact info
  const QB_CONFIG = {
    whatsappNumber: "201234567890", // ← Replace with your real WhatsApp number (no + or spaces)
    email: "hello@karimabdelaziz.com", // ← Replace with your real email
    calendlyUrl: "https://calendly.com/your-link", // ← Replace when ready
  };

  let qbState = {
    currentStep: 1,
    totalSteps: 5,
    data: { name: "", projectType: "", budget: "", timeline: "", details: "" },
  };

  // Open modal — accepts optional pre-context
  window.openQuickBrief = function (context) {
    const modal = document.getElementById("qbModal");
    if (!modal) return;
    modal.classList.add("open");
    document.body.style.overflow = "hidden";
    // Reset to step 1
    qbState.currentStep = 1;
    qbState.data = {
      name: "",
      projectType: "",
      budget: "",
      timeline: "",
      details: "",
    };
    showStep(1);
    updateProgress();
    updateNav();
    // Focus first input
    setTimeout(() => {
      const nameInput = document.getElementById("qbName");
      if (nameInput) nameInput.focus();
    }, 400);
  };

  window.closeQuickBrief = function () {
    const modal = document.getElementById("qbModal");
    if (!modal) return;
    modal.classList.remove("open");
    document.body.style.overflow = "";
  };

  function showStep(n) {
    document
      .querySelectorAll(".qb-step")
      .forEach((s) => s.classList.remove("qb-step-active"));
    const target = document.querySelector(`[data-step="${n}"]`);
    if (target) target.classList.add("qb-step-active");
    qbState.currentStep = n;
  }

  function updateProgress() {
    const pct = (qbState.currentStep / qbState.totalSteps) * 100;
    const fill = document.getElementById("qbProgressFill");
    if (fill) fill.style.width = pct + "%";
  }

  function updateNav() {
    const backBtn = document.getElementById("qbBackBtn");
    const nextBtn = document.getElementById("qbNextBtn");
    if (!backBtn || !nextBtn) return;

    // Back button
    backBtn.disabled = qbState.currentStep === 1;

    // Next button visibility - hidden on last step (replaced by send options)
    if (qbState.currentStep === qbState.totalSteps) {
      nextBtn.style.display = "none";
    } else {
      nextBtn.style.display = "";
      // Validate current step
      const valid = validateStep(qbState.currentStep);
      nextBtn.disabled = !valid;
    }
  }

  function validateStep(step) {
    switch (step) {
      case 1:
        return qbState.data.name.trim().length > 0;
      case 2:
        return !!qbState.data.projectType;
      case 3:
        return !!qbState.data.budget;
      case 4:
        return !!qbState.data.timeline;
      case 5:
        return true; // details is optional
      default:
        return true;
    }
  }

  window.qbNext = function () {
    if (
      qbState.currentStep < qbState.totalSteps &&
      validateStep(qbState.currentStep)
    ) {
      showStep(qbState.currentStep + 1);
      updateProgress();
      updateNav();
    }
  };

  window.qbBack = function () {
    if (qbState.currentStep > 1) {
      showStep(qbState.currentStep - 1);
      updateProgress();
      updateNav();
    }
  };

  // Wire up chips
  document.querySelectorAll(".qb-chips").forEach((group) => {
    group.addEventListener("click", (e) => {
      const chip = e.target.closest(".qb-chip");
      if (!chip) return;
      // Single-select within group
      group
        .querySelectorAll(".qb-chip")
        .forEach((c) => c.classList.remove("selected"));
      chip.classList.add("selected");
      const value = chip.dataset.value;
      // Save to state
      if (group.id === "qbProjectType") qbState.data.projectType = value;
      else if (group.id === "qbBudget") qbState.data.budget = value;
      else if (group.id === "qbTimeline") qbState.data.timeline = value;
      updateNav();
      // Auto-advance after selection (small delay for UX)
      setTimeout(() => {
        if (
          validateStep(qbState.currentStep) &&
          qbState.currentStep < qbState.totalSteps
        ) {
          qbNext();
        }
      }, 300);
    });
  });

  // Wire up text inputs
  const nameInput = document.getElementById("qbName");
  if (nameInput) {
    nameInput.addEventListener("input", (e) => {
      qbState.data.name = e.target.value;
      updateNav();
    });
    nameInput.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && validateStep(1)) {
        e.preventDefault();
        qbNext();
      }
    });
  }
  const detailsInput = document.getElementById("qbDetails");
  if (detailsInput) {
    detailsInput.addEventListener("input", (e) => {
      qbState.data.details = e.target.value;
    });
  }

  // Build the message
  function buildMessage() {
    const { name, projectType, budget, timeline, details } = qbState.data;
    let msg = `Hi Karim! 👋\n\nI'm ${name}, and I'd like to discuss a project.\n\n`;
    msg += `📋 Project Type: ${projectType}\n`;
    msg += `💰 Budget: ${budget}\n`;
    msg += `⏰ Timeline: ${timeline}\n`;
    if (details && details.trim()) {
      msg += `\n📝 Details:\n${details.trim()}\n`;
    }
    msg += `\nLooking forward to hearing from you!`;
    return msg;
  }

  // Send via chosen method
  window.sendQuickBrief = function (method) {
    const msg = buildMessage();
    let url;

    if (method === "whatsapp") {
      url = `https://wa.me/${QB_CONFIG.whatsappNumber}?text=${encodeURIComponent(msg)}`;
      window.open(url, "_blank");
    } else if (method === "email") {
      const subject = `New Project Inquiry — ${qbState.data.projectType} (${qbState.data.name})`;
      url = `mailto:${QB_CONFIG.email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(msg)}`;
      window.location.href = url;
    } else if (method === "meeting") {
      // For now, open WhatsApp with a meeting request (since Calendly not set up yet)
      const meetingMsg = `Hi Karim! 👋\n\nI'd like to book a meeting to discuss a project.\n\n📋 Project Type: ${qbState.data.projectType}\n💰 Budget: ${qbState.data.budget}\n⏰ Timeline: ${qbState.data.timeline}\n\nI'm ${qbState.data.name}. ${qbState.data.details ? "\n\nDetails: " + qbState.data.details : ""}\n\nWhat times work best for you?`;
      url = `https://wa.me/${QB_CONFIG.whatsappNumber}?text=${encodeURIComponent(meetingMsg)}`;
      window.open(url, "_blank");
    }

    // Track the contact automatically
    if (typeof window.trackContact === 'function') {
      window.trackContact(method);
    }

    closeQuickBrief();
  };

  // ESC to close
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") {
      const modal = document.getElementById("qbModal");
      if (modal && modal.classList.contains("open")) {
        closeQuickBrief();
      }
    }
  });
})();

// ═══════ SERVICES ROTATOR ═══════
(function () {
  const rotator = document.getElementById("svcRotator");
  if (!rotator) return;
  const words = rotator.querySelectorAll(".svc-rword");
  if (words.length < 2) return;
  let current = 0;

  setInterval(() => {
    const cur = words[current];
    const next = words[(current + 1) % words.length];

    // Exit current
    cur.classList.remove("active");
    cur.classList.add("exiting");

    // After exit anim, swap to next
    setTimeout(() => {
      cur.classList.remove("exiting");
      next.classList.add("active");
    }, 300);

    current = (current + 1) % words.length;
  }, 3200);
})();

