function renderFrontendAboutPage() {
  const stage = document.querySelector('.story-stage');
  const processGrid = document.querySelector('.process-grid-new');
  if (!stage || !processGrid) return;
  
  const d = window.ABOUT_DATA;
  
  // Render chapters
  // First clear old chapters and journey nodes
  stage.querySelectorAll('.story-chapter, .journey-node').forEach(el => el.remove());
  
  let journeyLine = stage.querySelector('.journey-line');
  if (journeyLine) {
    d.chapters.forEach((c, i) => {
      let node = document.createElement('div');
      node.className = 'journey-node';
      node.setAttribute('data-node', i + 1);
      journeyLine.appendChild(node);
    });
  }

  let chaptersHtml = '';
  d.chapters.forEach((c, i) => {
    let classes = ['story-chapter'];
    if (i % 2 !== 0 && c.visualType !== 'final') classes.push('story-chapter-reverse');
    if (c.visualType === 'final') classes.push('story-chapter-final');
    
    if (c.visualType === 'final') {
      chaptersHtml += `
        <div class="${classes.join(' ')}" data-story-chapter="${i+1}">
          <div class="story-content story-content-centered">
            <div class="story-eyebrow reveal-story"><span data-en="${esc(c.eyebrowEn)}" data-ar="${esc(c.eyebrowAr)}">${c.eyebrowEn}</span></div>
            <h2 class="story-title-big reveal-story" style="width: fit-content; margin-inline: auto; text-align: center;" data-en="${esc(c.titleEn)}" data-ar="${esc(c.titleAr)}">${c.titleEn}</h2>
            <p class="story-text-big reveal-story" data-en="${esc(c.textEn)}" data-ar="${esc(c.textAr)}">${c.textEn}</p>
            <div class="story-cta-wrap reveal-story">
              <a href="#contact" class="cta-primary">
                <span data-en="Let's create together" data-ar="خلينا نبدع سوا">Let's create together</span>
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M5 12h14"/><path d="M12 5l7 7-7 7"/></svg>
              </a>
            </div>
          </div>
        </div>
      `;
    } else {
      let statsHtml = '';
      if (c.stats && c.stats.length > 0) {
        statsHtml = '<div class="story-stats reveal-story">' + c.stats.map(s => `
          <div class="story-stat-item"><span class="story-stat-num" data-count-target="${s.target}">0</span><span class="story-stat-lbl" data-en="${esc(s.labelEn)}" data-ar="${esc(s.labelAr)}">${s.labelEn}</span></div>
        `).join('') + '</div>';
      }
      
      let yearHtml = '';
      if (c.yearEn) {
        yearHtml = `<div class="story-year reveal-story" data-en="${esc(c.yearEn)}" data-ar="${esc(c.yearAr)}">${c.yearEn}</div>`;
      }
      
      chaptersHtml += `
        <div class="${classes.join(' ')}" data-story-chapter="${i+1}">
          <div class="story-content">
            <div class="story-eyebrow reveal-story"><span data-en="${esc(c.eyebrowEn)}" data-ar="${esc(c.eyebrowAr)}">${c.eyebrowEn}</span></div>
            <h2 class="story-title reveal-story" data-en="${esc(c.titleEn)}" data-ar="${esc(c.titleAr)}">${c.titleEn}</h2>
            <p class="story-text reveal-story" data-en="${esc(c.textEn)}" data-ar="${esc(c.textAr)}">${c.textEn}</p>
            ${statsHtml}
            ${yearHtml}
          </div>
          <div class="story-visual">
            ${getChapterVisualHtml(c.visualType)}
          </div>
        </div>
      `;
    }
  });
  
  stage.insertAdjacentHTML('beforeend', chaptersHtml);
  
  // Render process steps
  // Clear old process cards except for the CTA at the end
  const processCards = processGrid.querySelectorAll('.process-card');
  processCards.forEach(card => card.remove());
  
  let processHtml = '';
  d.process.forEach((p, i) => {
    let rowClass = i < 2 ? 'top-row' : 'bottom-row'; // Assuming first 2 are top row if they exist
    processHtml += `
      <div class="process-card ${rowClass}">
        <div class="process-icon-wrap">
          ${getProcessIconHtml(p.icon)}
        </div>
        <h3 class="process-card-title" data-en="${esc(p.titleEn)}" data-ar="${esc(p.titleAr)}">${p.titleEn}</h3>
        <p class="process-card-desc" data-en="${esc(p.descEn)}" data-ar="${esc(p.descAr)}">${p.descEn}</p>
      </div>
    `;
  });
  
  // Insert before the contact CTA div
  const ctaDiv = processGrid.querySelector('div[style*="text-align:center"]');
  if (ctaDiv) {
    ctaDiv.insertAdjacentHTML('beforebegin', processHtml);
  } else {
    processGrid.innerHTML = processHtml;
  }
  
  if (window.updateStoryScrollNodes) {
    window.updateStoryScrollNodes();
  }
}

renderFrontendAboutPage();

window.openVideoModal = function(url) {
  const modal = document.getElementById('globalVideoModal');
  const iframe = document.getElementById('globalVideoIframe');
  if (modal && iframe) {
    let finalUrl = url;
    if (url.includes('youtube.com/watch?v=')) {
      finalUrl = url.replace('watch?v=', 'embed/');
    } else if (url.includes('youtu.be/')) {
      finalUrl = url.replace('youtu.be/', 'youtube.com/embed/');
    }
    iframe.src = finalUrl;
    modal.classList.add('active');
  }
};

window.closeVideoModal = function() {
  const modal = document.getElementById('globalVideoModal');
  const iframe = document.getElementById('globalVideoIframe');
  if (modal && iframe) {
    iframe.src = '';
    modal.classList.remove('active');
  }
};

window.renderFrontendTrainingPage = function() {
  const dStr = localStorage.getItem('ka_admin_training_data');
  if (!dStr) return;
  let d;
  try { d = JSON.parse(dStr); } catch(e) { return; }
  
  const section = document.getElementById('training');
  if (!section) return;

  const curLang = document.documentElement.lang === 'ar' ? 'ar' : 'en';
  const esc = str => (String(str || '')).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');

  const updateTxt = (el, enStr, arStr) => {
    if (!el) return;
    if (enStr) el.setAttribute('data-en', enStr);
    if (arStr) el.setAttribute('data-ar', arStr);
    el.innerHTML = esc(curLang === 'ar' ? (arStr || enStr) : (enStr || arStr));
  };

  updateTxt(section.querySelector('.eyebrow'), d.eyebrowEn, d.eyebrowAr);
  updateTxt(section.querySelector('.heading'), d.headingEn, d.headingAr);
  
  const card = section.querySelector('.training-card > div');
  if (card) {
    updateTxt(card.querySelector('h3'), d.cardTitleEn, d.cardTitleAr);
    const paras = card.querySelectorAll('p');
    if (paras[0]) updateTxt(paras[0], d.para1En, d.para1Ar);
    if (paras[1]) updateTxt(paras[1], d.para2En, d.para2Ar);
  }

  if (d.bullets && Array.isArray(d.bullets)) {
    const list = document.getElementById('frontendTrainingBullets');
    if (list) {
      list.innerHTML = d.bullets.map(b => `<li><span data-en="${esc(b.en)}" data-ar="${esc(b.ar)}">${esc(b[curLang] || b.en)}</span></li>`).join('');
    }
  }

  if (d.stats && Array.isArray(d.stats)) {
    const statsCont = section.querySelector('.training-stats');
    if (statsCont) {
      statsCont.innerHTML = d.stats.map(s => {
        const valHtml = s.target !== undefined && s.target !== ''
          ? `<span class="count" data-target="${esc(s.target)}" data-suffix="${esc(s.suffix||'')}">${esc(s.target)}${esc(s.suffix||'')}</span>`
          : esc(s.value||'');
        return `<div class="ts"><div class="ts-n fade-pulse">${valHtml}</div><div class="ts-l fade-pulse" data-en="${esc(s.labelEn)}" data-ar="${esc(s.labelAr)}">${esc(curLang === 'ar' ? s.labelAr : s.labelEn)}</div></div>`;
      }).join('');
    }
  }

  const vHead = section.querySelector('.video-reviews-header');
  if (vHead) {
    updateTxt(vHead.querySelector('h3'), d.videoHeadingEn, d.videoHeadingAr);
    updateTxt(vHead.querySelector('p'), d.videoSubEn, d.videoSubAr);
  }

  if (d.videos && Array.isArray(d.videos) && d.videos.length > 0) {
    const vGrid = section.querySelector('.video-reviews-grid');
    if (vGrid) {
      vGrid.innerHTML = d.videos.map(v => `
        <div class="video-card" onclick="window.openVideoModal('${esc(v.url)}')">
          <div class="video-card-glow"></div>
          <div class="video-card-bg"></div>
          <div class="video-card-quote">"</div>
          <div class="video-card-play"><svg viewBox="0 0 24 24"><polygon points="6,4 20,12 6,20"/></svg></div>
          <div class="video-card-info">
            <div class="video-card-text" data-en="${esc(v.textEn)}" data-ar="${esc(v.textAr)}">${esc(curLang === 'ar' ? v.textAr : v.textEn)}</div>
            <div class="video-card-name">${esc(v.name)}</div>
            <div class="video-card-role" data-en="${esc(v.roleEn)}" data-ar="${esc(v.roleAr)}">${esc(curLang === 'ar' ? v.roleAr : v.roleEn)}</div>
          </div>
        </div>
      `).join('');
    }
  }
};
window.renderFrontendTrainingPage();

